#[derive(Debug, Clone, Default)]
struct Definitions {
    font_assets: Vec<FontAssetDefinition>,
    image_assets: Vec<ImageAssetDefinition>,
    script_assets: Vec<ScriptAssetDefinition>,
    shader_assets: Vec<ShaderAssetDefinition>,
    data_converters: Vec<DataConverterDefinition>,
    view_models: Vec<ViewModelDefinition>,
    artboards: Vec<ArtboardDefinition>,
}

#[cfg(test)]
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct SceneWork {
    definition_index_builds: usize,
    definition_index_node_visits: usize,
    receipt_membership_checks: usize,
}

#[cfg(test)]
thread_local! {
    static SCENE_WORK: std::cell::Cell<SceneWork> = const {
        std::cell::Cell::new(SceneWork {
            definition_index_builds: 0,
            definition_index_node_visits: 0,
            receipt_membership_checks: 0,
        })
    };
}

#[cfg(test)]
fn reset_scene_work() {
    SCENE_WORK.set(SceneWork::default());
}

#[cfg(test)]
fn scene_work() -> SceneWork {
    SCENE_WORK.get()
}

#[cfg(test)]
fn record_scene_work(update: impl FnOnce(&mut SceneWork)) {
    SCENE_WORK.with(|cell| {
        let mut work = cell.get();
        update(&mut work);
        cell.set(work);
    });
}

impl Definitions {
    fn canonicalize_and_validate(
        &mut self,
        operation_index: usize,
    ) -> std::result::Result<(), EditAbort> {
        Hierarchy::canonicalize_and_validate(self, operation_index)
    }
}

#[derive(Debug, Clone, Copy)]
struct IndexedObject {
    artboard: ArtboardId,
    artboard_index: usize,
    record_index: usize,
    kind: AuthoredObjectKind,
}

impl IndexedObject {
    const fn visual_kind(self) -> Option<NodeKind> {
        match self.kind {
            AuthoredObjectKind::Visual(kind) => Some(kind),
            _ => None,
        }
    }
}

/// Transaction-local identity and parent lookup. Structural operations may do
/// deep candidate work, but the high-volume create path and receipt filtering
/// never rescan the growing authored graph.
#[derive(Default)]
struct DefinitionIndex {
    font_assets: BTreeMap<FontAssetId, usize>,
    image_assets: BTreeMap<ImageAssetId, usize>,
    script_assets: BTreeMap<ScriptAssetId, usize>,
    shader_assets: BTreeMap<ShaderAssetId, usize>,
    data_converters: BTreeMap<DataConverterId, usize>,
    view_models: BTreeMap<ViewModelId, usize>,
    view_model_numbers: BTreeMap<ViewModelNumberId, (usize, usize)>,
    view_model_strings: BTreeMap<ViewModelStringId, (usize, usize)>,
    view_model_booleans: BTreeMap<ViewModelBooleanId, (usize, usize)>,
    view_model_colors: BTreeMap<ViewModelColorId, (usize, usize)>,
    view_model_images: BTreeMap<ViewModelImageId, (usize, usize)>,
    view_model_enums: BTreeMap<ViewModelEnumId, (usize, usize)>,
    view_model_triggers: BTreeMap<ViewModelTriggerId, (usize, usize)>,
    view_model_list_indices: BTreeMap<ViewModelListIndexId, (usize, usize)>,
    view_model_lists: BTreeMap<ViewModelListId, (usize, usize)>,
    view_model_children: BTreeMap<ViewModelChildId, (usize, usize)>,
    view_model_instances: BTreeMap<ViewModelInstanceId, (usize, usize)>,
    artboards: BTreeMap<ArtboardId, usize>,
    objects: BTreeMap<ObjectId, IndexedObject>,
    children: BTreeMap<Parent, Vec<ObjectId>>,
    owned: BTreeMap<ObjectId, Vec<ObjectId>>,
    keyed_objects: BTreeMap<(ObjectId, ObjectId), ObjectId>,
    keyed_properties: BTreeMap<(ObjectId, ExportedAnimatableProperty), ObjectId>,
    key_frames: BTreeMap<(ObjectId, u32), ObjectId>,
}

impl DefinitionIndex {
    fn build(definitions: &Definitions) -> Self {
        #[cfg(test)]
        record_scene_work(|work| {
            work.definition_index_builds = work.definition_index_builds.saturating_add(1);
            work.definition_index_node_visits = definitions
                .artboards
                .iter()
                .fold(work.definition_index_node_visits, |visits, artboard| {
                    visits.saturating_add(artboard.records.len())
                });
        });
        let mut index = Self::default();
        for (font_index, font) in definitions.font_assets.iter().enumerate() {
            index.font_assets.insert(font.id, font_index);
        }
        for (image_index, image) in definitions.image_assets.iter().enumerate() {
            index.image_assets.insert(image.id, image_index);
        }
        for (script_index, script) in definitions.script_assets.iter().enumerate() {
            index.script_assets.insert(script.id, script_index);
        }
        for (shader_index, shader) in definitions.shader_assets.iter().enumerate() {
            index.shader_assets.insert(shader.id, shader_index);
        }
        for (converter_index, converter) in definitions.data_converters.iter().enumerate() {
            index.data_converters.insert(converter.id, converter_index);
            index.owned.entry(converter.id.object_id()).or_default();
        }
        for (view_model_index, view_model) in definitions.view_models.iter().enumerate() {
            index.view_models.insert(view_model.id, view_model_index);
            index.owned.entry(view_model.id.object_id()).or_default();
            for (number_index, number) in view_model.numbers.iter().enumerate() {
                index
                    .view_model_numbers
                    .insert(number.id, (view_model_index, number_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(number.id.object_id());
                index.owned.entry(number.id.object_id()).or_default();
            }
            for (string_index, string) in view_model.strings.iter().enumerate() {
                index
                    .view_model_strings
                    .insert(string.id, (view_model_index, string_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(string.id.object_id());
                index.owned.entry(string.id.object_id()).or_default();
            }
            for (boolean_index, boolean) in view_model.booleans.iter().enumerate() {
                index
                    .view_model_booleans
                    .insert(boolean.id, (view_model_index, boolean_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(boolean.id.object_id());
                index.owned.entry(boolean.id.object_id()).or_default();
            }
            for (color_index, color) in view_model.colors.iter().enumerate() {
                index
                    .view_model_colors
                    .insert(color.id, (view_model_index, color_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(color.id.object_id());
                index.owned.entry(color.id.object_id()).or_default();
            }
            for (image_index, image) in view_model.images.iter().enumerate() {
                index
                    .view_model_images
                    .insert(image.id, (view_model_index, image_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(image.id.object_id());
                index.owned.entry(image.id.object_id()).or_default();
            }
            for (enum_index, enum_property) in view_model.enums.iter().enumerate() {
                index
                    .view_model_enums
                    .insert(enum_property.id, (view_model_index, enum_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(enum_property.id.object_id());
                index.owned.entry(enum_property.id.object_id()).or_default();
            }
            for (trigger_index, trigger) in view_model.triggers.iter().enumerate() {
                index
                    .view_model_triggers
                    .insert(trigger.id, (view_model_index, trigger_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(trigger.id.object_id());
                index.owned.entry(trigger.id.object_id()).or_default();
            }
            for (list_index_index, list_index) in view_model.list_indices.iter().enumerate() {
                index
                    .view_model_list_indices
                    .insert(list_index.id, (view_model_index, list_index_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(list_index.id.object_id());
                index.owned.entry(list_index.id.object_id()).or_default();
            }
            for (list_index, list) in view_model.lists.iter().enumerate() {
                index
                    .view_model_lists
                    .insert(list.id, (view_model_index, list_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(list.id.object_id());
                index.owned.entry(list.id.object_id()).or_default();
            }
            for (child_index, child) in view_model.children.iter().enumerate() {
                index
                    .view_model_children
                    .insert(child.id, (view_model_index, child_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(child.id.object_id());
                index.owned.entry(child.id.object_id()).or_default();
            }
            for (instance_index, instance) in view_model.instances.iter().enumerate() {
                index
                    .view_model_instances
                    .insert(instance.id, (view_model_index, instance_index));
                index
                    .owned
                    .entry(view_model.id.object_id())
                    .or_default()
                    .push(instance.id.object_id());
                index.owned.entry(instance.id.object_id()).or_default();
            }
        }
        for (artboard_index, artboard) in definitions.artboards.iter().enumerate() {
            index.artboards.insert(artboard.id, artboard_index);
            index
                .children
                .entry(Parent::Artboard(artboard.id))
                .or_default();
            for (record_index, record) in artboard.records.iter().enumerate() {
                index.objects.insert(
                    record.id,
                    IndexedObject {
                        artboard: artboard.id,
                        artboard_index,
                        record_index,
                        kind: record.spec.kind(),
                    },
                );
                index.owned.entry(record.id).or_default();
                if let Some(owner) = record.spec.owner() {
                    index.owned.entry(owner).or_default().push(record.id);
                }
                match &record.spec {
                    RecordSpec::Visual { parent, .. } => {
                        index.children.entry(*parent).or_default().push(record.id);
                        index.children.entry(Parent::Object(record.id)).or_default();
                    }
                    RecordSpec::Animation(AnimationRecordSpec::KeyedObject {
                        animation,
                        target,
                    }) => {
                        index.keyed_objects.insert((*animation, *target), record.id);
                    }
                    RecordSpec::Animation(AnimationRecordSpec::KeyedProperty {
                        keyed_object,
                        property,
                    }) => {
                        index
                            .keyed_properties
                            .insert((*keyed_object, *property), record.id);
                    }
                    RecordSpec::Animation(AnimationRecordSpec::KeyFrameDouble {
                        keyed_property,
                        frame,
                        ..
                    })
                    | RecordSpec::Animation(AnimationRecordSpec::KeyFrameColor {
                        keyed_property,
                        frame,
                        ..
                    }) => {
                        index
                            .key_frames
                            .insert((*keyed_property, *frame), record.id);
                    }
                    RecordSpec::Animation(AnimationRecordSpec::LinearAnimation(_))
                    | RecordSpec::Machine(_)
                    | RecordSpec::VisibilityBind(_)
                    | RecordSpec::TextBind(_)
                    | RecordSpec::NumberBind(_) => {}
                }
            }
        }
        index
    }

    fn contains_object(&self, object: ObjectId) -> bool {
        self.objects.contains_key(&object)
            || self
                .data_converters
                .keys()
                .any(|id| id.object_id() == object)
            || self.view_models.keys().any(|id| id.object_id() == object)
            || self
                .view_model_numbers
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_strings
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_booleans
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_colors
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_images
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_enums
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_triggers
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_list_indices
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_lists
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_children
                .keys()
                .any(|id| id.object_id() == object)
            || self
                .view_model_instances
                .keys()
                .any(|id| id.object_id() == object)
    }

    fn rebuild(&mut self, definitions: &Definitions) {
        *self = Self::build(definitions);
    }

    fn validate_parent(
        &self,
        operation_index: usize,
        parent: Parent,
        child: NodeKind,
    ) -> std::result::Result<ArtboardId, EditAbort> {
        match parent {
            Parent::Artboard(artboard) => {
                if !valid_artboard_child(child) {
                    return Err(EditAbort::new(
                        operation_index,
                        vec![EditId::Artboard(artboard)],
                        EditReason::InvalidParent {
                            parent: None,
                            child,
                        },
                    ));
                }
                self.artboards
                    .contains_key(&artboard)
                    .then_some(artboard)
                    .ok_or_else(|| {
                        EditAbort::new(
                            operation_index,
                            vec![EditId::Artboard(artboard)],
                            EditReason::UnknownArtboard,
                        )
                    })
            }
            Parent::Object(object) => {
                let Some(parent) = self.objects.get(&object).copied() else {
                    return Err(EditAbort::new(
                        operation_index,
                        vec![EditId::Object(object)],
                        EditReason::UnknownObject,
                    ));
                };
                let Some(parent_kind) = parent.visual_kind() else {
                    return Err(EditAbort::new(
                        operation_index,
                        vec![EditId::Object(object)],
                        EditReason::NonVisualObject,
                    ));
                };
                if !valid_object_parent(parent_kind, child) {
                    return Err(EditAbort::new(
                        operation_index,
                        vec![EditId::Object(object)],
                        EditReason::InvalidParent {
                            parent: Some(parent_kind),
                            child,
                        },
                    ));
                }
                Ok(parent.artboard)
            }
        }
    }
}

#[derive(Default)]
struct SpecOrigins {
    font_assets: BTreeMap<FontAssetId, usize>,
    image_assets: BTreeMap<ImageAssetId, usize>,
    script_assets: BTreeMap<ScriptAssetId, usize>,
    shader_assets: BTreeMap<ShaderAssetId, usize>,
    artboard_specs: BTreeMap<ArtboardId, usize>,
    nodes: BTreeMap<ObjectId, usize>,
    properties: BTreeMap<(ObjectId, &'static str), usize>,
    relationships: BTreeMap<ObjectId, usize>,
}

impl SpecOrigins {
    fn font_asset(&self, id: FontAssetId, fallback: usize) -> usize {
        self.font_assets.get(&id).copied().unwrap_or(fallback)
    }

    fn image_asset(&self, id: ImageAssetId, fallback: usize) -> usize {
        self.image_assets.get(&id).copied().unwrap_or(fallback)
    }

    fn script_asset(&self, id: ScriptAssetId, fallback: usize) -> usize {
        self.script_assets.get(&id).copied().unwrap_or(fallback)
    }

    fn shader_asset(&self, id: ShaderAssetId, fallback: usize) -> usize {
        self.shader_assets.get(&id).copied().unwrap_or(fallback)
    }

    fn artboard(&self, id: ArtboardId, fallback: usize) -> usize {
        self.artboard_specs.get(&id).copied().unwrap_or(fallback)
    }

    fn object(&self, id: ObjectId, fallback: usize) -> usize {
        self.nodes.get(&id).copied().unwrap_or(fallback)
    }

    fn property(&self, id: ObjectId, property: &'static str, fallback: usize) -> usize {
        self.properties
            .get(&(id, property))
            .copied()
            .unwrap_or_else(|| self.object(id, fallback))
    }

    fn relationship(&self, first: ObjectId, second: ObjectId, fallback: usize) -> usize {
        [first, second]
            .into_iter()
            .flat_map(|id| {
                [
                    self.nodes.get(&id).copied(),
                    self.relationships.get(&id).copied(),
                ]
            })
            .flatten()
            .max()
            .unwrap_or(fallback)
    }
}

