fn encode_runtime_id_path(path: &[u32]) -> Vec<u8> {
    let mut encoded = Vec::new();
    for id in path {
        let mut value = *id;
        loop {
            let mut byte = (value & 0x7f) as u8;
            value >>= 7;
            if value != 0 {
                byte |= 0x80;
            }
            encoded.push(byte);
            if value == 0 {
                break;
            }
        }
    }
    encoded
}

